MERGE INTO CONSULTAS FIN USING (SELECT '800630PreviewCausacionPPTAL' INFORME ,TO_CLOB(q'[SELECT 
TIPO_CPTE TIPO, TO_CHAR(COMPROBANTE) NUMERO, TO_CHAR(FECHA, 'DD/MM/YYYY') AS FECHA, DESCRIPCION, CUENTA RUBRO, VALOR_DEBITO VALOR ,TERCERO, TERCERO.NOMBRE NOMBRETERCERO, CENTRO_COSTO, AUXILIAR, FUENTE_RECURSO, REFERENCIA
FROM
TEMP_DETALLE_COMPROBANTE_PPTAL
  INNER JOIN TERCERO 
     ON TEMP_DETALLE_COMPROBANTE_PPTAL.COMPANIA = TERCERO.COMPANIA
    AND TEMP_DETALLE_COMPROBANTE_PPTAL.TERCERO = TERCERO.NIT
    AND TEMP_DETALLE_COMPROBANTE_PPTAL.SUCURSAL = TERCERO.SUCURSAL
    WHERE TEMP_DETALLE_COMPROBANTE_PPTAL.COMPANIA = s$compania$s
AND TEMP_DETALLE_COMPROBANTE_PPTAL.ANO = s$ano$s
AND TEMP_DETALLE_COMPROBANTE_PPTAL.COMPROBANTE = s$numero$s
AND TEMP_DETALLE_COMPROBANTE_PPTAL.TIPO_CPTE = 's$tipo$s']') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'mrosero' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);